int alarms = 0;
for (int h = 1; h <= 24; h++)
{
    ushort temp = Plc.ReadHoldingRegister(100);
    if (temp > 300) { alarms++; Print($"{h}:00 报警! {temp/10.0:F1}°C"); }
    Plc.WriteHoldingRegister(100, (ushort)(temp + 2));
}
Print($"总巡检24次，报警{alarms}次，正常率{(24-alarms)*100.0/24:F1}%");
Print("巡检完成");
